class T(unittest.TestCase):
    @unittest.expectedFailure
    def test_expected_failure(self):
        self.assertEqual(1, 0)

    @unittest.expectedFailure
    def test_expected_failure_but_successful(self):
        self.assertEqual(1, 1)

if __name__ == '__main__':
